    def login(self):
        if self.UsernameE.text() == "test" and self.PasswordE.text() == "1234":
            self.LogError.setText("")
            self.update()
            self.Scereens.setCurrentIndex(2)
            self.pending()
        else:
            self.LogError.setText("Error loging in, password or username are incorrect")
            self.update()


    def pending(self):
        global values, status
        self.SaveConfirm.setText("")
        self.ConTitle.setText("You are now in: pending")
        self.HelpS.setText("You can search for pending contacts with name, phone number, or email")
        self.menubar.clear()
        goto=self.menubar.addMenu("Go to")
        pending=goto.addAction("pending")
        pending.triggered.connect(self.pending)
        continued=goto.addAction("continued")
        continued.triggered.connect(self.continued)
        rejected=goto.addAction("rejected")
        rejected.triggered.connect(self.Rejected)
        Logout=self.menubar.addAction("Logout")
        Logout.triggered.connect(self.logout)
        self.update()
        self.NameList.clear()
        self.StatusList.clear()
        self.visible_rows = []
        values=Database_control.get_raw_data(Database_control.get_sheet_vals(Database_control.sheet_id))
        for i in range(len(values)):
            row_status = values[i][11] if len(values[i]) > 11 else ""
            if str(row_status).strip().lower()=="pending":
                self.NameList.addItem(values[i][1])
                self.StatusList.addItem("pending")
                self.visible_rows.append((i + 2, values[i]))
            elif row_status in (None, ""):
                Database_control.update_status(Database_control.sheet_id, i+2, 12, "pending")
                if len(values[i]) > 11:
                    values[i][11] = "pending"
                self.NameList.addItem(values[i][1])
                self.StatusList.addItem("pending")
                self.visible_rows.append((i + 2, values[i]))
        status="pending"

