    def search(self):
        global values, status
        self.NameList.clear()
        self.StatusList.clear()
        self.visible_rows = []
        search_text = self.SearchE.text()
        for i in range(len(values)):
            if search_text in str(values[i][1]) or search_text in str(values[i][2]) or search_text in str(values[i][5]) or search_text in str(values[i][6]) or search_text in str(values[i][7]) or search_text in str(values[i][8]) or search_text in str(values[i][9]):
                if values[i][11]==status:
                    self.NameList.addItem(values[i][1])
                    self.StatusList.addItem(values[i][11])
                    self.visible_rows.append((i + 2, values[i]))

    def contactinfo(self):
        global values, status
        self.menubar.clear()
        i=self.NameList.currentRow()
        if i < 0 or i >= len(self.visible_rows):
            return
        self.Scereens.setCurrentIndex(1)
        self.selected_sheet_row, selected_row = self.visible_rows[i]
        self.ParentNameE.setText(str(selected_row[1]))
        self.ChildNameE.setText(str(selected_row[2]))
        self.ChildAgeE.setText(str(selected_row[3]))
        self.ChildGradeE.setText(str(selected_row[4]))
        self.ParentEmailE.setText(str(selected_row[5]))
        self.ParentNumberE.setText(str(selected_row[6]))
        self.SecondaryParentNameE.setText(str(selected_row[7]))
        self.SecondaryParentEmailE.setText(str(selected_row[8]))
        self.SecondaryParentNumE.setText(str(selected_row[9]))
        self.FilledFromE.setText(str(selected_row[10]))
        self.update()
        try:
            self.SaveBT1.clicked.disconnect()
        except TypeError:
            pass
        try:
            self.SaveBT2.clicked.disconnect()
        except TypeError:
            pass
        self.SaveBT1.setText("Save to rejected")
        self.SaveBT2.setText("Save to continued")
        if status == "pending":
            self.SaveBT1.setEnabled(True)
            self.SaveBT1.clicked.connect(self.save_rejected)
            self.SaveBT2.setEnabled(True)
            self.SaveBT2.clicked.connect(self.save_continued)
        elif status == "continued":
            self.SaveBT1.setEnabled(True)
            self.SaveBT1.clicked.connect(self.save_rejected)
            self.SaveBT2.setEnabled(False)
        elif status == "rejected":
            self.SaveBT2.setEnabled(True)
            self.SaveBT2.clicked.connect(self.save_continued)
            self.SaveBT1.setEnabled(False)

    def back(self):
        self.Scereens.setCurrentIndex(2)


    def finish_save_and_return(self, refresh_view):
        self.SaveConfirm.setText("")
        refresh_view()
        self.Scereens.setCurrentIndex(2)


    def save_continued(self):
        if self.selected_sheet_row is not None and status!="continued":
            Database_control.update_status(Database_control.sheet_id, self.selected_sheet_row, 12, "continued")
            self.SaveConfirm.setText("Saved to continued")
            self.update()
            if status=="pending":
                QtCore.QTimer.singleShot(1000, lambda: self.finish_save_and_return(self.pending))
            elif status=="rejected":
                QtCore.QTimer.singleShot(1000, lambda: self.finish_save_and_return(self.Rejected))

    def save_rejected(self):
        if self.selected_sheet_row is not None and status!="rejected":
            Database_control.update_status(Database_control.sheet_id, self.selected_sheet_row, 12, "rejected")
            self.SaveConfirm.setText("Saved to rejected")
            self.update()
            if status=="pending":
                QtCore.QTimer.singleShot(1000, lambda: self.finish_save_and_return(self.pending))
            elif status=="continued":
                QtCore.QTimer.singleShot(1000, lambda: self.finish_save_and_return(self.continued))
    def logout(self):
        self.Scereens.setCurrentIndex(0)
        self.menubar.clear()


